const now = new Date();
const kst = new Date(now.getTime() + 9 * 60 * 60 * 1000);
const day = kst.getUTCDay();
const hour = kst.getUTCHours();
const minute = kst.getUTCMinutes();
const totalMinutes = hour * 60 + minute;
const marketOpen = 9 * 60;
const marketClose = 15 * 60 + 30;
const isWeekday = day >= 1 && day <= 5;
const isMarketHours = totalMinutes >= marketOpen && totalMinutes <= marketClose;
return [{ json: { isOpen: isWeekday && isMarketHours } }];

const COOLDOWN_MS = 30 * 60 * 1000;
const data = $json;

if (!data.success || !data.triggered) {
  return [{ json: { shouldAlert: false, reason: data.triggered ? 'api_error' : 'not_triggered' } }];
}

const staticData = $getWorkflowStaticData('global');
const lastAlertTime = staticData.lastAlertTime || 0;
const now = Date.now();

if (now - lastAlertTime < COOLDOWN_MS) {
  return [{ json: { shouldAlert: false, reason: 'cooldown', lastAlertTime } }];
}

staticData.lastAlertTime = now;

const condLines = data.conditions.map(c => {
  const icon = c.met ? '✅' : '❌';
  return `- ${icon} ${c.detail || c.name}`;
}).join('\n');

const msg = `🔴 [매도 검토] ${data.name} (${data.symbol})\n충족 조건: ${data.conditions_met}/${data.conditions.length}\n${condLines}`;

return [{ json: { shouldAlert: true, message: msg, symbol: data.symbol, name: data.name, conditions_met: data.conditions_met } }];
